export function init() {
  console.log('[SignupRoute] Initialized');

  const form = document.getElementById('signupForm');
  const submitBtn = form.querySelector('button[type="submit"]');

  // Password toggle functionality
  setupPasswordToggle('togglePassword', 'password', 'eyeIcon');
  setupPasswordToggle('toggleConfirmPassword', 'confirmPassword', 'eyeIconConfirm');

  // Sign In link - publish topic
  const signinLink = document.querySelector('.auth-switch a[href="#/signin"]');
  signinLink?.addEventListener('click', (e) => {
    e.preventDefault();
    PubSub.publish(AppBroadcast.AUTH_SIGNIN);
  });

  // Form submission
  form.addEventListener('submit', async (e) => {
    e.preventDefault();

    const first = document.getElementById('first').value.trim();
    const last = document.getElementById('last').value.trim();
    const email = document.getElementById('email').value.trim();
    const company = document.getElementById('company').value.trim();
    const phone = document.getElementById('phone').value.trim();
    const password = document.getElementById('password').value;
    const confirmPassword = document.getElementById('confirmPassword').value;

    const firstInput = document.getElementById('first');
    const lastInput = document.getElementById('last');
    const emailInput = document.getElementById('email');
    const passwordInput = document.getElementById('password');
    const confirmPasswordInput = document.getElementById('confirmPassword');

    // Validate first name
    if (!validateField(first, firstInput, 'Please enter your first name')) {
      return;
    }

    // Validate last name
    if (!validateField(last, lastInput, 'Please enter your last name')) {
      return;
    }

    // Validate email
    if (!validateEmail(email, emailInput)) {
      return;
    }

    // Validate password
    if (!validatePassword(password, passwordInput)) {
      return;
    }

    // Validate password match
    if (password !== confirmPassword) {
      shakeAndToast(confirmPasswordInput, 'Passwords do not match');
      return;
    }

    // Disable button
    submitBtn.disabled = true;
    submitBtn.textContent = 'Creating account...';

    // Proceed with signup
    await handleSignup(first, last, email, company, phone, password);
  });
}

/**
 * Setup password toggle button
 */
function setupPasswordToggle(buttonId, inputId, iconId) {
  const toggleBtn = document.getElementById(buttonId);
  const passwordInput = document.getElementById(inputId);
  const eyeIcon = document.getElementById(iconId);

  if (!toggleBtn || !passwordInput || !eyeIcon) return;

  toggleBtn.addEventListener('click', () => {
    const isPassword = passwordInput.type === 'password';
    passwordInput.type = isPassword ? 'text' : 'password';

    // Toggle eye icon (eye-off when showing password)
    if (isPassword) {
      eyeIcon.innerHTML = `
        <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"></path>
        <line x1="1" y1="1" x2="23" y2="23"></line>
      `;
    } else {
      eyeIcon.innerHTML = `
        <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path>
        <circle cx="12" cy="12" r="3"></circle>
      `;
    }
  });
}

/**
 * Validate required field - shake and toast on error
 */
function validateField(value, inputElement, errorMessage) {
  if (!value) {
    shakeAndToast(inputElement, errorMessage);
    return false;
  }
  return true;
}

/**
 * Validate email field - shake and toast on error
 */
function validateEmail(email, inputElement) {
  // Check if empty
  if (!email) {
    shakeAndToast(inputElement, 'Please enter your email');
    return false;
  }

  // Check format (must contain exactly one @ and at least one .)
  const atCount = (email.match(/@/g) || []).length;
  const dotCount = (email.match(/\./g) || []).length;

  if (atCount !== 1 || dotCount < 1) {
    shakeAndToast(inputElement, 'Please enter a valid email address');
    return false;
  }

  return true;
}

/**
 * Validate password - shake and toast on error
 * Uses shared password validator with strong requirements:
 * - Minimum 10 characters
 * - At least 1 lowercase letter
 * - At least 1 uppercase letter
 * - At least 1 special character
 * - ASCII characters only
 */
function validatePassword(password, inputElement) {
  if (!password) {
    shakeAndToast(inputElement, 'Please enter a password');
    return false;
  }

  const errors = validatePasswordStrength(password);
  if (errors.length > 0) {
    shakeAndToast(inputElement, formatPasswordErrors(errors));
    return false;
  }

  return true;
}

/**
 * Shake animation and toast notification
 */
function shakeAndToast(element, message) {
  // Toast notification
  if (typeof neodigmToast !== 'undefined') {
    neodigmToast.q(message, 'danger');
  }

  // Shake animation
  if (typeof neodigmUtils !== 'undefined') {
    neodigmUtils.shake(`#${element.id}`);
  } else {
    element.classList.add('shake');
    setTimeout(() => element.classList.remove('shake'), 300);
  }

  element.focus();
}

/**
 * Handle signup API call
 */
async function handleSignup(first, last, email, company, phone, password) {
  const submitBtn = document.querySelector('button[type="submit"]');

  try {
    // Hash password
    const hash = genHash(password);

    // Build account data
    const accountData = {
      email,
      hash,
      first,
      last
    };

    if (company) accountData.company = company;
    if (phone) accountData.phone = phone;

    // Call signup endpoint
    const response = await AuthController.doSignup(accountData);

    if (response.ok) {
      // Success - publish event
      PubSub.publish(AppBroadcast.AUTH_SIGNUP_SUCCESS, {
        email
      });

      // Navigate to unverified state
      if (typeof mvvLegit !== 'undefined') {
        mvvLegit.doUNVERF();
      }
    } else {
      // Error from API
      const errorMessage = response.error || response.message || 'Sign up failed';

      if (typeof neodigmToast !== 'undefined') {
        neodigmToast.q(errorMessage, 'danger');
      }

      submitBtn.disabled = false;
      submitBtn.textContent = 'CREATE ACCOUNT';

      PubSub.publish(AppBroadcast.AUTH_SIGNUP_FAIL, {
        message: errorMessage
      });
    }
  } catch (error) {
    console.error('[SignupRoute] Sign up error:', error);

    if (typeof neodigmToast !== 'undefined') {
      neodigmToast.q(error.message || 'Network error - please try again', 'danger');
    }

    submitBtn.disabled = false;
    submitBtn.textContent = 'CREATE ACCOUNT';

    PubSub.publish(AppBroadcast.AUTH_SIGNUP_FAIL, {
      message: error.message
    });
  }
}
