/**
 * Splash Route - Landing page
 */

import PubSub from 'pubsub-js';
import AppBroadcast from '../core/appBroadcast.js';

export function render() {
  return `
    <div class="splash-container">
      <div class="splash-content">
        <h1>StreamSyncEngage</h1>
        <p class="tagline">Real-time messaging and account management platform</p>

        <div class="splash-actions">
          <button class="btn btn-primary" data-nav="signin">
            Sign In
          </button>
          <button class="btn btn-secondary" data-nav="signup">
            Sign Up
          </button>
        </div>

        <div class="splash-info">
          <p>Please check your email to verify your account if you just signed up.</p>
        </div>
      </div>
    </div>

    <style>
      .splash-container {
        display: flex;
        justify-content: center;
        align-items: center;
        min-height: 100vh;
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        padding: 20px;
      }

      .splash-content {
        text-align: center;
        color: white;
        max-width: 500px;
      }

      .splash-content h1 {
        font-size: 3rem;
        margin-bottom: 1rem;
        font-weight: 700;
      }

      .tagline {
        font-size: 1.2rem;
        margin-bottom: 2rem;
        opacity: 0.9;
      }

      .splash-actions {
        display: flex;
        gap: 1rem;
        justify-content: center;
        margin-bottom: 2rem;
      }

      .btn {
        padding: 12px 24px;
        border: none;
        border-radius: 6px;
        font-size: 1rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
      }

      .btn-primary {
        background: white;
        color: #667eea;
      }

      .btn-primary:hover {
        transform: translateY(-2px);
        box-shadow: 0 4px 12px rgba(255, 255, 255, 0.3);
      }

      .btn-secondary {
        background: rgba(255, 255, 255, 0.2);
        color: white;
        border: 2px solid white;
      }

      .btn-secondary:hover {
        background: rgba(255, 255, 255, 0.3);
        transform: translateY(-2px);
      }

      .splash-info {
        margin-top: 2rem;
        padding: 1rem;
        background: rgba(255, 255, 255, 0.1);
        border-radius: 8px;
        font-size: 0.9rem;
      }
    </style>
  `;
}

export function init() {
  console.log('[SplashRoute] Initialized');

  // Attach navigation event listeners
  document.querySelectorAll('[data-nav]').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const route = e.target.getAttribute('data-nav');
      console.log('[SplashRoute] Button clicked, navigating to:', route);

      // Publish navigation event
      PubSub.publish(AppBroadcast.ROUTE_NAV, { route });

      // Also navigate directly via hash change (Navigo will pick it up)
      window.location.hash = `#/${route}`;
    });
  });

  console.log('[SplashRoute] Attached click handlers to', document.querySelectorAll('[data-nav]').length, 'buttons');
}
