/**
 * Home Route - User dashboard (authenticated)
 */

// Import web component to register it
import '../wc/m5t-primary-nav.js';
import PubSub from 'pubsub-js';
import AppBroadcast from '../core/appBroadcast.js';
import AuthController from '../services/AuthController.js';

export function render() {
  return `
    <div class="home-container">
      <m5t-primary-nav
        data-buttons='[
          {"token": "DASHBOARD", "caption": "Dashboard", "enabled": true, "selected": true},
          {"token": "ANALYTICS", "caption": "Analytics", "enabled": true},
          {"token": "MESSAGES", "caption": "Messages", "enabled": true, "count": 3},
          {"token": "SETTINGS", "caption": "Settings", "enabled": true},
          {"token": "RESET_PASSWORD", "caption": "Reset Password", "enabled": true},
          {"token": "SIGN_OUT", "caption": "Sign Out", "enabled": true}
        ]'
      ></m5t-primary-nav>

      <main class="home-main">
        <h1>Welcome to StreamSyncEngage</h1>
      </main>
    </div>

    <style>
      * {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
      }

      .home-container {
        min-height: 100vh;
        background: #6c757d;
        padding: 16px;
      }

      .home-main {
        max-width: 1200px;
        margin: 120px auto 0;
        padding: 2rem;
        color: white;
        text-align: center;
      }

      .home-main h1 {
        font-size: 2.5rem;
        margin-bottom: 2rem;
      }
    </style>
  `;
}

export function init() {
  console.log('[HomeRoute] Initialized');

  // Listen for navigation events
  const nav = document.querySelector('m5t-primary-nav');
  
  if (nav) {
    nav.addEventListener('nav-select', (e) => {
      const token = e.detail.token;
      console.log('[HomeRoute] Nav button clicked:', token);
      
      switch(token) {
        case 'DASHBOARD':
          PubSub.publish(AppBroadcast.UI_TOAST, {
            message: 'Dashboard view',
            type: 'info'
          });
          break;
          
        case 'ANALYTICS':
          PubSub.publish(AppBroadcast.UI_TOAST, {
            message: 'Analytics view coming soon',
            type: 'info'
          });
          break;
          
        case 'MESSAGES':
          PubSub.publish(AppBroadcast.UI_TOAST, {
            message: '3 new messages',
            type: 'info'
          });
          break;
          
        case 'SETTINGS':
          PubSub.publish(AppBroadcast.UI_TOAST, {
            message: 'Settings view',
            type: 'info'
          });
          break;
          
        case 'RESET_PASSWORD':
          console.log('[HomeRoute] Reset password requested');
          PubSub.publish(AppBroadcast.AUTH_RESETHASH_NAV);
          break;
          
        case 'SIGN_OUT':
          console.log('[HomeRoute] Sign out requested');
          AuthController.navigateTo('signout');
          break;
      }
    });

  }
}
