/**
 * Sign Out Route
 * Two-panel grid layout matching signin/signup pattern
 * Grayscale colors only from launCh.css
 */

import AuthController from '../services/AuthController.js';

export function render() {
  return `
    <div class="auth-container">
      <div class="auth-left">
        <h1>Sign Out</h1>
        <p>Are you sure you want to sign out?</p>

        <div class="auth-content">
          <button id="confirm-signout-btn" class="btn">SIGN OUT</button>

          <p class="auth-switch">
            <a id="cancel-signout-btn" class="link-brand--uc__underline" href="#/home">CANCEL</a>
          </p>
        </div>
      </div>

      <div class="auth-right">
        <div class="auth-right-content">
          <div class="h-display__portrait--none">
            <br><br>
          </div>
          <h5 class="auth-hero-title">
            Taking a break? We'll keep your data safe.
          </h5>
          <p class="auth-hero-description">
            You can sign back in anytime to continue managing your instant messages, notifications, and engagement campaigns.
          </p>
        </div>
      </div>
    </div>
  `;
}

export function init() {
  console.log('[SignoutRoute] Initialized');

  const confirmBtn = document.getElementById('confirm-signout-btn');

  // Confirm signout
  confirmBtn?.addEventListener('click', async () => {
    confirmBtn.disabled = true;
    confirmBtn.textContent = 'SIGNING OUT...';

    console.log('[SignoutRoute] User confirmed signout');

    // Call AuthController.doSignout() - handles API call, token clearing, and hard refresh
    await AuthController.doSignout();

    // Note: Hard refresh will occur, so code below won't execute
  });
}
